//line main.kuki:315
func gatherPrompt(args []string) string {
//line main.kuki:316
	prompt := ""
//line main.kuki:319
	if !isTerminal(os.Stdin) && (len(args) == 0) {
//line main.kuki:320
		data, err_46 := io.ReadAll(os.Stdin)
//line main.kuki:320
		if err_46 != nil {
//line main.kuki:320
			//line main.kuki:321
			data = []byte{}
		}
//line main.kuki:323
		prompt = strpkg.TrimSpace(string(data))
	}
//line main.kuki:325
	if len(args) > 0 {
//line main.kuki:326
		argText := strpkg.Join(args, " ")
//line main.kuki:327
		if prompt != "" {
//line main.kuki:328
			prompt = fmt.Sprintf("%v\n\n%v", argText, prompt)
		} else {
//line main.kuki:330
			prompt = argText
		}
	}
//line main.kuki:332
	return prompt
}

